// Extract the top trader's wallet address from leaderboard
const leaders = $('Get Leaderboard').all();
if (!leaders.length || !leaders[0].json.proxyWallet) {
  return [{ json: { walletAddress: null, error: 'No leaderboard data' } }];
}

const topTrader = leaders[0].json;
return [{
  json: {
    walletAddress: topTrader.proxyWallet,
    userName: topTrader.userName || 'Top Trader',
    pnl: topTrader.pnl || 0,
    volume: topTrader.volume || 0
  }
}];

// Combine all data sources into a single context block for AI
const leaders = $('Get Leaderboard').all();
const markets = $('Search Trending Markets').all();
const whaleTrades = $input.all();

// Format leaderboard
const leaderboardText = leaders.map((l, i) => {
  const d = l.json;
  return `${i + 1}. ${d.userName || 'Anon'} -- PnL: $${Number(d.pnl || 0).toLocaleString()}, Volume: $${Number(d.volume || 0).toLocaleString()}`;
}).join('\n');

// Format trending markets
const marketsText = markets.slice(0, 10).map((m, i) => {
  const d = m.json;
  const prices = typeof d.outcomePrices === 'string' ? JSON.parse(d.outcomePrices) : (d.outcomePrices || []);
  const yesPrice = prices[0] ? `${(Number(prices[0]) * 100).toFixed(0)}%` : 'N/A';
  return `${i + 1}. "${d.question || d.title || 'Unknown'}" -- Yes: ${yesPrice}, Volume: $${Number(d.volume || 0).toLocaleString()}`;
}).join('\n');

// Format whale trades
const whaleText = whaleTrades.map(t => {
  const d = t.json;
  const side = (d.side || d.type || 'UNKNOWN').toUpperCase();
  return `- ${side} ${d.market || d.question || 'Unknown'} -- ${d.size || d.amount || '?'} shares at $${Number(d.price || 0).toFixed(2)}`;
}).join('\n');

const contextBlock = `TODAY'S POLYMARKET DATA\n\n` +
  `TOP TRADERS (24h):\n${leaderboardText}\n\n` +
  `TRENDING MARKETS:\n${marketsText}\n\n` +
  `WHALE TRADES (top trader's recent activity):\n${whaleText}`;

return [{ json: { contextBlock } }];

// Extract the generated content from OpenAI response
const response = $input.first().json;
let drafts = '';
try {
  drafts = response.choices[0].message.content;
} catch (e) {
  drafts = 'ERROR: Could not parse OpenAI response.';
}
return [{ json: { drafts } }];

// Combine original drafts + voice review into final Telegram message
const drafts = $('Extract Drafts').first().json.drafts;
const reviewResponse = $input.first().json;
let review = '';
try {
  review = reviewResponse.choices[0].message.content;
} catch (e) {
  review = 'Voice review failed. Sending original drafts.';
}

const today = new Date().toLocaleDateString('en-US', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

const message = `REVIEW & POST\n${today}\n${'='.repeat(40)}\n\nVOICE-REVIEWED CONTENT:\n\n${review}\n\n${'='.repeat(40)}\nORIGINAL DRAFTS (before review):\n\n${drafts}\n\n${'='.repeat(40)}\nPost the voice-reviewed versions. Edit further if needed.`;

return [{ json: { message } }];
